def set_note(value):
    state.note = value


def reset_controls():
    state.batch_update(
        name="Ada",
        enabled=True,
        level=3,
        theme="System",
        note="",
    )


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("输入", [
                appui.TextField(
                    "Name",
                    text=state.name,
                    on_change=set_name,
                    submit_label="done",
                ),
                appui.TextEditor(text=state.note, on_change=set_note)
                    .frame(height=80),
                appui.Toggle("Enabled", is_on=state.enabled, on_change=set_enabled),
            ]),
            appui.Section("选择", [
                appui.Slider(
                    value=state.level,
                    minimum=0,
                    maximum=10,
                    step=1,
                    label=f"Level {state.level}",
