        ]).navigation_title("AppUI")
    )


appui.run(body, state=state) 预期效果：预览打开一个原生表单页面，点击按钮后当前值立即更新。 先选写法 目标 推荐看 第一次写 MiniApp [快速上手](appui-quickstart.md) 判断该用 AppUI、widget、ui 还是 scene [运行时选择](miniapp-choose-runtime.md) 选择页面结构 [AppUI UI 模式](miniapp-appui-ui-patterns.md) 按任务查 API [AppUI API 地图](miniapp-appui-api-index.md) 排查空白、按钮、输入、列表和权限问题 [MiniApp 开发排错](miniapp-dev-troubleshooting.md) 查完整函数和组件 [函数参考](appui-ref-functions.md) 写 AppUI 的心智模型 入口：脚本末尾调用一次 appui.run(body, state=state)。 页面：body() 或 body(view_state) 返回一个 AppUI View。 状态：State 保存普通界面数据，ReactiveState 只用于高频变化。 绑定：bind() / State.bind() 适合输入控件和状态双向连接。 结构：设置页用 Form + Section，列表页用 List + ForEach，多页面用 NavigationStack 或 TabView。 交互：按钮、输入、搜索、刷新和弹层使用命名回调修改状态。 副作用：联网、文件、权限、通知和耗时任务不要写在 body() 里。 适用场景 需求 首选 表单、设置、列表、详情、工具页 `appui` 多页面 MiniApp、Tab、弹层、搜索、刷新 `appui` 图表、媒体、地图、WebView 和系统能力入口 `appui` + 对应模块 主屏、锁屏、StandBy 小组件 `widget` Sprite、碰撞、逐帧绘制、小游戏 `scene` Pythonista 兼容的命令式界面脚本 `ui` 纯输出、批处理、日志转换 普通 Python / `console` 行为契约 API 保证 注意 `appui.run(...)` 启动一个 MiniApp 预览或页面。 放在脚本末尾，一个脚本只保留一个入口。 `appui.run(..., presentation=...)` 控制界面呈现方式。 可选 `'sheet'`（默认）、`'fullscreen'`、`'fullscreen_with_close'`。 `State` 字段变化后触发页面重建。 多字段同时更新优先用 `batch_update(...)`。 `ReactiveState` 适合高频数据更新。 普通表单和列表不要默认使用。 `body()` 描述当前界面。 不要在里面发请求、申请权限、写文件或修改状态。 `Button(action=...)` 点击后执行命名回调。 传函数本身，不要写 `action=save()`。 `ForEach(..., key=...)` 用稳定 key 维护动态行身份。 不要把可变化的 index 当 key。 API 参考 分类 文档 函数与入口 [函数参考](appui-ref-functions.md) 状态与绑定 [状态 API](appui-ref-state.md) 布局容器 [布局 API](appui-ref-layout.md) 控件 [控件参考](appui-ref-controls.md) 导航 [导航参考](appui-ref-navigation.md) 呈现和数据展示 [呈现参考](appui-ref-presentation.md)、[数据展示](appui-ref-data.md) 修饰符 [修饰符参考](appui-ref-modifiers.md) 图表、媒体、地图、形状 [图表](appui-ref-charts.md)、[媒体](appui-ref-media.md)、[形状](appui-ref-shapes.md) 失败路径 预览空白：确认 body() 返回 AppUI View，脚本末尾调用了 appui.run(...)。 按钮没反应：确认 action 传入命名函数，而不是函数调用结果。 输入不更新：确认 on_change 接收新值并写回 State。 列表错行：确认 ForEach 使用稳定 key。 页面不像原生设置：设置页优先用 Form + Section，不要用一组自绘卡片模拟。 权限或网络反复弹出：确认副作用没有写进 body()。 模块兼容性 appui 与 ui 有 View、Button、TextField、Slider、Image、ScrollView 等同名类/函数，但语义不同。不要在同一文件中同时 from appui import 和 from ui import 。 appui 与 scene 只有 run 这个入口名容易混淆。混用时用模块名限定调用：appui.run(body) / scene.run(MyScene())。

快速上手 用四个可预览示例掌握 body、State、控件和导航。 appui 开始 appui quickstart preview 快速上手 hello state button tabview previewAppUI 快速上手 这篇教程用四个可预览示例串起 AppUI 的最小闭环：显示页面、修改状态、编辑表单、列表进详情。每段都可以直接运行。 1. Hello World 先让原生页面出现。body() 返回一个 View，脚本末尾调用 appui.run(body)。 import appui


def body():
    return appui.NavigationStack(
        appui.VStack([
            appui.Text("Hello AppUI").font("title2").bold(),
            appui.Text("用 Python 编写原生 MiniApp 界面")
            .foreground_color("secondaryLabel"),
        ], spacing=8)
        .padding()
        .navigation_title("Hello")
    )


appui.run(body) 预期效果：预览显示一个带导航标题的原生页面，页面中有标题和说明文字。 2. State 和按钮 用 State 保存页面数据。按钮回调修改状态后，页面会用新状态重建。 import appui

state = appui.State(count=0, message="Ready")


def decrease():
    state.batch_update(count=state.count - 1, message="Decreased")


def increase():
    state.batch_update(count=state.count + 1, message="Increased")


def body(view_state):
    return appui.NavigationStack(
        appui.VStack([
            appui.Text(f"当前计数：{view_state.count}").font("title3"),
            appui.HStack([
                appui.Button("-1", action=decrease).button_style("bordered"),
                appui.Button("+1", action=increase)
                .button_style("bordered_prominent"),
            ], spacing=12),
            appui.Text(view_state.message)
            .font("caption")
            .foreground_color("secondaryLabel"),
        ], spacing=16)
        .padding()
        .navigation_title("状态")
    )


appui.run(body, state=state) 预期效果：点击 +1 或 1 后计数和状态文案同步变化。 3. 表单控件 设置页和编辑页优先使用 Form + Section。输入控件通过 on_change 写回 State。 import appui

state = appui.State(name="Ada", enabled=False, volume=40.0, saved=False)


def set_name(value):
    state.batch_update(name=value, saved=False)


def set_enabled(value):
    state.batch_update(enabled=value, saved=False)


def set_volume(value):
    state.batch_update(volume=value, saved=False)


def save():
    state.saved = bool(state.name.strip())


def body():
    footer = "已保存" if state.saved else "修改后点击保存"
    return appui.NavigationStack(
        appui.Form([
            appui.Section("资料", [
                appui.TextField("姓名", text=state.name, on_change=set_name),
                appui.Toggle("启用提醒", is_on=state.enabled, on_change=set_enabled),
                appui.Slider(
                    value=state.volume,
                    minimum=0,
                    maximum=100,
                    on_change=set_volume,
                ),
            ], footer=footer),
            appui.Section("操作", [
                appui.Button("保存", action=save)
                .button_style("bordered_prominent"),
            ]),
        ]).navigation_title("表单")
    )


appui.run(body, state=state) 预期效果：修改文本、开关或滑块后页面保持响应；点击保存后底部文案变为“已保存”。 4. 导航和列表 多页面 MiniApp 通常用 NavigationStack 包根页面，列表进详情用 NavigationLink。动态行必须有稳定 key。 import appui

items = [
    {"id": "docs", "title": "文档", "subtitle": "Guide"},
    {"id": "api", "title": "API", "subtitle": "Reference"},
    {"id": "demo", "title": "示例", "subtitle": "Cookbook"},
]

state = appui.State(last_opened="None")


def item_key(item):
    return item["id"]


def mark_opened(item):
    state.last_opened = item["title"]


def detail_view(item):
    def open_current():
        mark_opened(item)

    return appui.Form([
        appui.Section("详情", [
            appui.LabeledContent("标题", value=item["title"]),
            appui.LabeledContent("类型", value=item["subtitle"]),
            appui.Button("标记打开", action=open_current),
        ]),
        appui.Section("状态", [
            appui.LabeledContent("Last opened", value=state.last_opened),
        ]),
    ]).navigation_title(item["title"])


def row_view(item):
    label = appui.HStack([
        appui.Text(item["title"])
        .frame(max_width=appui.infinity, alignment="leading"),
        appui.Text(item["subtitle"]).foreground_color("secondaryLabel"),
    ])
    return appui.NavigationLink(destination=detail_view(item), label=label)


def body():
    return appui.NavigationStack(
        appui.List([
            appui.Section("入口", [
                appui.ForEach(items, row_builder=row_view, key=item_key),
            ])
        ]).navigation_title("列表")
    )


appui.run(body, state=state) 预期效果：列表显示三行入口，点击任一行进入详情页；详情页按钮会更新打开状态。 发布前检查 检查项 合格标准 入口 脚本末尾只调用一次 `appui.run(...)` 呈现 默认 `presentation='sheet'`；全屏可用 `'fullscreen'` 或 `'fullscreen_with_close'` 页面 `body()` 或 `body(state)` 返回 AppUI View 状态 回调修改 `State`，多字段更新用 `batch_update(...)` 按钮 `action` 传命名函数，不写 `action=save()` 输入 `on_change` 接收新值并写回 `State` 列表 `ForEach` 使用稳定 `key` 失败路径 预览空白：确认 body() 返回 View，且脚本末尾调用了 appui.run(...)。 按钮没反应：确认 action 传函数本身，而不是函数调用结果。 输入不更新：确认 on_change 的参数名接收新值，并写回 State。 列表详情错乱：确认 ForEach 使用稳定业务 id，不使用会变化的 index。 页面越来越难维护：回到 AppUI UI 模式，先选页面结构。 API 参考 继续查 AppUI API 地图。需要判断该用哪个运行时时，先看 运行时选择。

运行时选择 判断该用 appui、widget、ui、scene 还是 console。 appui 开始 Runtime Decision 运行时 appui scene console web 怎么选 表单 导航 媒体 图表 运行时选择 MiniApp 先选运行时，再写代码。运行时选错会让布局难维护、交互不可用、系统能力接不上。 默认判断 大多数“像 App 一样能点、能输入、能保存状态”的需求，默认选 appui。只有当需求明确是小组件、游戏绘制、Pythonista 兼容 UI 或纯输出脚本时，才换运行时。 决策表 需求 首选运行时 不建议 原生表单、列表、导航、设置页、工具页 `appui` 用 HTML 模拟 iOS 设置页 主屏、锁屏、StandBy 小组件 `widget` 用 AppUI 写桌面 Widget 命令输出、批处理、日志 `console` 为纯输出脚本硬做 UI 绘制、小游戏、精灵、连续触摸 `scene` 用 AppUI 手写游戏循环 Pythonista 兼容的命令式界面脚本 `ui` 和 `appui` 混用通配导入 已有 Web 页面或必须使用 DOM/CSS/JS HTML / `WebView` 为普通工具页引入 Web 结构 相机、定位、通知、存储等系统能力 `appui` + 对应模块 在 Web 页面里绕过原生能力 AppUI 骨架 import appui

state = appui.State(status="Ready")


def run_action():
    state.status = "Action completed"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("MiniApp", [
                appui.LabeledContent("Runtime", value="appui"),
                appui.LabeledContent("Status", value=state.status),
                appui.Button("Run", action=run_action)
                .button_style("bordered_prominent"),
            ])
        ]).navigation_title("运行时")
    )


appui.run(body, state=state) 预期效果：预览显示一个原生表单页面，点击 Run 后状态变为 Action completed。 不同运行时的边界 widget 用于主屏、锁屏和 StandBy 小组件。它没有普通页面输入和长列表交互，适合信息展示、参数配置、时间线刷新和受控桌面按钮。 console 用于一次性脚本、批处理、日志输出和转换任务。用户只需要看输出时，不要硬做 AppUI。 scene 用于持续绘制、游戏、精灵、物理和触摸循环。它不是设置页、列表页或表单页的替代品。 ui 用于 Pythonista 兼容的命令式界面脚本。新 MiniApp 默认不要从 ui 开始；需要原生 App 风格页面时用 appui。 HTML / WebView 用于已有 Web 页面、必须复用 DOM/CSS/JS 的内容，或需要展示外部网页。普通 iOS 风格工具页不建议用 Web 结构模拟。 选择规则 不确定时先选 appui，因为它覆盖表单、列表、导航、设置和大多数工具页。 用户要求“桌面小组件、主屏卡片、锁屏信息”，选 widget。 用户要求“小游戏、画布、碰撞、持续动画”，选 scene。 只有输出、批处理或转换任务时，选 console。 需要设备能力时，先查 原生能力入口。 失败路径 页面像网页而不是原生 App：回到 appui，使用 NavigationStack、Form、List。 小组件脚本无法输入文字：这是 widget 的边界；需要输入时做 AppUI 页面。 动画不连续：AppUI 适合界面状态动画；游戏循环和持续绘制交给 scene。 命令脚本维护成本变高：如果只是输出文本，保持 console，不要额外做页面。 相关文档 文档 用途 [快速上手](appui-quickstart.md) 跑通第一个 AppUI MiniApp。 [AppUI UI 模式](miniapp-appui-ui-patterns.md) 选择页面结构和常见模式。 [AppUI API 地图](miniapp-appui-api-index.md) 按任务查 API。 [MiniApp 开发排错](miniapp-dev-troubleshooting.md) 排查入口、状态、布局和系统能力。

appui 思维方式 从命令式 UI 切到 State 驱动的声明式 View 树。 appui 指南 appui concept state 思维方式 声明式 State body View appui 思维方式 appui 的核心规则很简单：body() 返回一棵 View 树，状态变化后重新计算这棵树。不要手动创建、保存、移动原生控件；只描述当前状态下界面应该是什么样。 预期效果 运行示例后会看到计数、登录分支和导航路径随状态变化即时刷新，页面代码始终只描述当前 View 树。 先记住这 4 条 规则 含义 View 是描述 `Text`、`Button`、`VStack` 只是声明界面结构。 State 是事实源 用户输入、选择、列表数据放进 `State` / `ReactiveState`。 body 要可重复执行 `body()` 里不要写网络请求、文件写入、定时器创建等副作用。 修饰符有顺序 `.padding().background()` 和 `.background().padding()` 的视觉结果不同。 从命令式切到声明式 命令式 UI 常见写法是“找到控件，然后改它”。appui 的写法是“改状态，然后让界面重新声明”。 import appui

state = appui.State(count=0)


def increment():
    state.count += 1


def body():
    return appui.VStack([
        appui.Text(f"Count: {state.count}")
            .font("largeTitle")
            .bold(),
        appui.Button("Add", action=increment)
            .button_style("bordered_prominent"),
    ], spacing=16).padding()


appui.run(body, state=state) 这段代码里没有“更新 label 文本”的命令。按钮只修改 state.count，下一次重建时 Text 自然显示新值。 View 树 View 可以嵌套，也可以根据状态返回不同分支。 import appui

state = appui.State(logged_in=False)


def log_in():
    state.logged_in = True


def body():
    if state.logged_in:
        content = appui.Text("已登录").font("title2")
    else:
        content = appui.Button("登录", action=log_in)

    return appui.VStack([
        appui.Text("欢迎").font("largeTitle").bold(),
        content,
    ], spacing=20).padding()


appui.run(body, state=state) 条件分支应该返回完整的 View。不要在 body() 外保存某个 View 再反复修改它。 State 先行 写界面前先列状态字段： 场景 推荐状态 普通字段、表单、开关 `State` 高频数值，如 slider、拖动、图表数据 `ReactiveState` 不触发重建的对象句柄 `Ref` 列表 / 字典增删改 `ObservableList` / `ObservableDict` 状态写入通常放在按钮、输入框绑定、手势或定时器回调里。多个字段一起改时用 state.batch_update(...)，避免中间状态触发多次重建。 修饰符链 修饰符返回新的 View 描述，因此可以连续调用： (
    appui.Text("Hello")
    .font("title")
    .foreground_color("white")
    .padding()
    .background("systemBlue")
    .corner_radius(12)
) 常用顺序是：内容样式 尺寸/间距 背景/边框 交互/导航。遇到视觉不对，优先检查修饰符顺序。 导航也是数据 导航栈不要当成“打开页面”的命令集合，而是一个路径状态。 import appui

path = appui.NavigationPath()
state = appui.State()


def open_settings():
    path.append({"tag": "settings"})


def go_back():
    path.pop()


def settings_destination(data):
    return appui.VStack([
        appui.Text("设置").font("title2"),
        appui.Button("返回", action=go_back),
    ], spacing=12).padding()


def body():
    return appui.NavigationStack(
        content=appui.VStack([
            appui.Text("首页").navigation_title("示例"),
            appui.Button("去设置页", action=open_settings),
        ], spacing=16).padding(),
        path=path,
        destinations={
            "settings": settings_destination,
        },
    )


appui.run(body, state=state) destinations 的回调会接收 data 参数；即使暂时不用，也要写成命名函数，避免把页面构造逻辑藏在内联回调里。 常见误区 误区 改法 在 `body()` 里创建定时器或发请求 放到 `effect`、按钮回调或生命周期回调。 把 View 保存到全局变量里再修改 保存状态，不保存 View。 列表原地改了但界面不刷新 使用 `ObservableList`，或重新赋值一个新列表。 参数名不确定 以 API 参考和代码补全为准。 一个 `body()` 写成几百行 拆成普通 Python 函数返回子 View。 下一步 状态管理 了解 State、ReactiveState、Ref 的边界。 布局系统 学会 Stack、Grid、ScrollView 和安全区。 导航与呈现 学会 NavigationStack、sheet、alert、popover。

交互与回调 按钮、输入、on_change、sheet 和行级回调的可靠写法。 appui 指南 appui callback button interaction 回调 callback lambda Button on_change on_dismiss 交互与回调 触摸、长按、拖拽与捏合等交互通过视图修饰符绑定到 Python 回调。键盘与焦点用 .focused 与 .keyboard_dismiss 控制；上下文菜单用 .context_menu；需要与系统手势共存时用 .simultaneous_gesture 或 .high_priority_gesture。 预期效果 示例会展示点击、长按、焦点、键盘、拖拽和行级动作的反馈路径。 概念速览 能力 API 点击 / 长按 `.on_tap(action)`、`.on_long_press(...)` 拖移 / 捏合 / 旋转 `.on_drag`、`.on_magnification`、`.on_rotation` 组合手势 `.simultaneous_gesture(...)`、`.high_priority_gesture(...)` 菜单 `.context_menu(content=[...])` 焦点与键盘 `.focused(...)`、`.keyboard_dismiss(mode)` 禁用 `.disabled(value)` 气泡菜单 `.popover(is_presented, content, on_dismiss)` 搜索和刷新 `.searchable(...)`、`.refreshable(...)` 列表动作 `.swipe_actions(...)` 手势优先级 普通子视图手势：默认由子控件（如 Button）消费点击。 simultaneous_gesture：与视图自身手势并行，适合在可滚动区域附加轻量检测。 high_priority_gesture：优先于子视图；仅在确有需要时使用，否则容易导致按钮点不动。 context_menu 的 content 是 Button 视图列表，不要用任意字符串代替 Button。 基础示例 点击计数、长按提示、context_menu 弹出操作。示例使用命名回调，预览里每个动作都有状态反馈。 import appui

state = appui.State(count=0, hint="")


def add_count():
    state.count += 1


def reset_count():
    state.batch_update(count=0, hint="已归零")


def double_count():
    state.batch_update(count=state.count * 2, hint="已加倍")


def show_long_press_hint():
    state.hint = "长按已触发"


def body():
    block = (
        appui.RoundedRectangle(corner_radius=16)
        .fill("systemBlue")
        .frame(width=140, height=90)
        .on_tap(add_count)
        .on_long_press(action=show_long_press_hint, min_duration=0.4)
        .context_menu(content=[
            appui.Button("归零", action=reset_count),
            appui.Button("加倍", action=double_count),
        ])
    )

    return appui.NavigationStack(
        appui.ScrollView(
            appui.VStack([
                appui.Text(f"计数: {state.count}").font("title"),
                appui.Text(state.hint or "点击或长按蓝色块")
                    .font("footnote")
                    .foreground_color("secondaryLabel"),
                block,
            ], spacing=20).padding()
        )
        .keyboard_dismiss("interactive")
        .navigation_title("交互示例")
    )


appui.run(body, state=state) 焦点、键盘和 Popover focused(key=..., equals=...) 适合多个输入字段之间切换焦点。keyboard_dismiss("interactive") 通常加在 ScrollView 或列表外层。 import appui

