                .symbol_rendering_mode("palette")
                .image_scale("large")
                .frame(width=56, height=56)
                .foreground_color("systemYellow"),
            appui.Label("设置", system_image="gear"),
        ], spacing=16).padding()
        .navigation_title("Image")
    )


