示例：网络列表 加载状态、刷新、错误展示和远端数据列表。 appui 示例 appui cookbook network list 网络列表 loading error refreshable 网络请求列表 MiniApp 演示 network.get 拉取 JSON、加载/错误状态与可搜索列表展示。 预期效果 运行后会出现带加载状态的网络列表，刷新、错误展示和空状态都在同一页面闭环。 适合场景 API 列表、远程内容流、搜索结果页。 需要加载中、失败、空结果和下拉刷新状态的页面。 页面结构 区域 结构 作用 顶层 `NavigationStack` 页面标题和系统搜索栏。 操作区 `Section + Button` 用户主动触发网络请求。 结果区 `Section + ForEach` 稳定渲染远程数据。 失败/空状态 `ContentUnavailableView` 避免请求失败后空白。 完整示例 import appui
import network

state = appui.State(
    loading=False,
    error="",
    query="",
    items=[
        {"id": "sample-1", "title": "示例数据", "subtitle": "点击刷新后替换为接口结果"},
    ],
)


def set_query(value):
    state.query = str(value)


def load_data():
    state.loading = True
    state.error = ""
    try:
        if not network.is_connected():
            state.error = "当前没有网络连接"
            return
        resp = network.get("https://jsonplaceholder.typicode.com/posts", timeout=15)
        if not resp.ok:
            state.error = f"HTTP {resp.status}"
            return
        data = resp.json()
        rows = []
        for item in data[:20]:
            rows.append({
                "id": str(item.get("id", len(rows))),
                "title": str(item.get("title", "Untitled")),
                "subtitle": str(item.get("body", ""))[:120],
            })
        state.items = rows
    except Exception as exc:
        state.error = str(exc)
    finally:
        state.loading = False


def filtered_items():
    q = state.query.strip().lower()
    if not q:
        return state.items
    return [
        item for item in state.items
        if q in item["title"].lower() or q in item["subtitle"].lower()
    ]


def item_key(item):
    return item["id"]


def row(item):
    return appui.VStack(
        [
            appui.Text(item["title"]).font("headline"),
            (
                appui.Text(item["subtitle"])
                .font("subheadline")
                .foreground_color("secondaryLabel")
                .line_limit(2)
            ),
        ],
        alignment="leading",
        spacing=4,
    )


def body():
    result_items = filtered_items()
    result_content = []
    if state.loading:
        result_content.append(appui.ProgressView("正在加载..."))
    elif state.error:
        result_content.append(
            appui.ContentUnavailableView(
                "请求失败",
                system_image="wifi.exclamationmark",
                description=state.error,
            )
        )
    elif not result_items:
        result_content.append(
            appui.ContentUnavailableView(
                "没有结果",
                system_image="doc.text.magnifyingglass",
                description="换个关键词或点击刷新数据。",
            )
        )
    else:
        result_content.append(appui.ForEach(result_items, row_builder=row, key=item_key))

    return appui.NavigationStack(
        appui.List(
            [
                appui.Section(
                    [
                        appui.Button("刷新数据", action=load_data)
                            .button_style("bordered_prominent"),
                    ],
                    header="API",
                    footer="示例接口仅用于演示，请替换为自己的 API。",
                ),
                appui.Section(result_content, header="结果"),
            ]
        )
        .searchable(text=state.query, on_change=set_query)
        .refreshable(load_data)
        .navigation_title("网络列表")
    )


appui.run(body, state=state, presentation="fullscreen_with_close") 关键技巧 在按钮回调里发起请求，不要在 body() 里直接请求。 resp.ok 只表示 HTTP 成功，业务字段仍需自行校验；失败时把 error 文案显示出来避免空白页。 动态远程数据使用 ForEach(..., key=...)，不要直接把筛选后的下标当身份。 可替换点 当前写法 可替换为 演示接口 你的业务 API `network.get(...)` `network.request(...)` / `network.post(...)` `state.items` `storage.get_json(...)` 作为离线缓存

示例：血压分析 HealthKit 授权、血压查询、摘要统计和趋势图。 appui 示例 appui cookbook health chart 血压 HealthKit query_blood_pressure summarize_blood_pressure Chart 血压分析 演示 health 授权、query_blood_pressure 与 appui 列表、分段 Picker、Chart 展示趋势与记录。 预期效果 运行后会出现血压分析页，授权、最新读数、趋势图和异常空状态都有对应展示。 完整示例 import time
import appui
import health

READ_TYPES = ["blood_pressure", "blood_pressure_systolic", "blood_pressure_diastolic"]


def sample_records():
    now = time.time()
    rows = []
    values = [(118, 76), (121, 78), (116, 74), (124, 80), (119, 77), (122, 79), (117, 75)]
    for index, pair in enumerate(values):
        ts = now - (len(values) - index) * 86400
        rows.append({
            "systolic": pair[0],
            "diastolic": pair[1],
            "unit": "mmHg",
            "start": ts,
            "end": ts,
        })
    return rows


initial_records = sample_records()

state = appui.State(
    days="30",
    records=initial_records,
    summary=health.summarize_blood_pressure(initial_records),
    source="示例数据",
    loading=False,
    message="真机授权后可读取 HealthKit 血压数据",
)


def date_label(timestamp):
    return time.strftime("%m/%d %H:%M", time.localtime(float(timestamp)))


def load_health_data():
    state.loading = True
    end = time.time()
    start = end - int(state.days) * 86400
    records = []

    if health.is_available():
        health.request_authorization(read=READ_TYPES)
        records = health.query_blood_pressure(start=start, end=end)

    if records:
        source = "HealthKit"
        message = f"读取 {len(records)} 条血压记录"
    else:
        records = sample_records()
        source = "示例数据"
        message = "未读取到 HealthKit 血压记录，当前显示示例数据"

    state.batch_update(
        records=records,
        summary=health.summarize_blood_pressure(records),
        source=source,
        message=message,
        loading=False,
    )


def set_days(value):
    state.days = value
    load_health_data()


def record_start(item):
    return float(item.get("start", 0))


def chart_rows(field):
    rows = sorted(state.records, key=record_start)[-14:]
    return [
        {
            "day": time.strftime("%m/%d", time.localtime(float(item.get("start", 0)))),
            "value": float(item.get(field, 0)),
        }
        for item in rows
    ]


def stat_text(field, label):
    summary = state.summary or {}
    stats = summary.get(field, {})
    if not stats:
        return appui.LabeledContent(label, value="--")
    return appui.LabeledContent(
        label,
        value=f'{stats["avg"]:.0f} / {stats["min"]:.0f}-{stats["max"]:.0f} mmHg',
    )


def record_row(item):
    return appui.HStack(
        [
            appui.VStack(
                [
                    appui.Text(date_label(item.get("start", 0))).font("headline"),
                    (
                        appui.Text(item.get("unit", "mmHg"))
                        .font("caption")
                        .foreground_color("secondaryLabel")
                    ),
                ],
                alignment="leading",
            ),
            appui.Spacer(),
            (
                appui.Text(
                    f'{item.get("systolic", 0):.0f}/'
                    f'{item.get("diastolic", 0):.0f}'
                )
                .font("title3")
                .bold()
            ),
        ],
        spacing=12,
    )


def record_key(item):
    return item.get("start", 0)


def body():
    latest = (state.summary or {}).get("latest") or {}
    return appui.NavigationStack(
        appui.List(
            [
                appui.Section(
                    [
                        appui.LabeledContent("数据源", value=state.source),
                        appui.LabeledContent("状态", value=state.message),
                        appui.Picker(
                            "时间范围",
                            selection=state.days,
                            options=["7", "30", "90"],
                            on_change=set_days,
                        ).picker_style("segmented"),
                        appui.Button("刷新 HealthKit", action=load_health_data)
                            .button_style("bordered_prominent"),
                    ],
                    header="同步",
                    footer="本示例只做个人数据统计和可视化，不提供医疗诊断。",
                ),
                appui.Section(
                    [
                        appui.LabeledContent(
                            "最近一次",
                            value=(
                                f'{latest.get("systolic", 0):.0f}/'
                                f'{latest.get("diastolic", 0):.0f} mmHg'
                            )
                            if latest else "--",
                        ),
                        stat_text("systolic", "收缩压 均值/范围"),
                        stat_text("diastolic", "舒张压 均值/范围"),
                    ],
                    header="摘要",
                ),
                appui.Section(
                    [
                        appui.Chart(
                            chart_rows("systolic"),
                            x="day",
                            y="value",
                            type="line",
                            color="systemRed",
                        )
                            .frame(height=180),
                        appui.Chart(
                            chart_rows("diastolic"),
                            x="day",
                            y="value",
                            type="line",
                            color="systemBlue",
                        )
                            .frame(height=180),
                    ],
                    header="趋势",
                ),
                appui.Section(
                    [appui.ForEach(state.records[:20], record_row, key=record_key)],
                    header="记录",
                ),
            ]
        )
        .refreshable(load_health_data)
        .navigation_title("血压")
    )


appui.run(body, state=state, presentation="sheet") 关键技巧 授权时同时申请 blood_pressure 与 systolic/diastolic 类型，兼容组合样本与数量样本。 query_blood_pressure 返回配对 mmHg；无数据时可回落示例集合并标明数据源。 summarize_blood_pressure 仅作统计展示，非诊断依据。

