dialogs 原生对话框、表单和日期选择。 iOS 原生模块 基础与权限 Dialog Form Date Picker dialogs alert input_alert list_dialog form_dialog date_dialog dialogs 阻塞式原生对话框：确认、输入、列表选择、简单表单和日期选择。 边界 ：调用会 阻塞脚本 直到用户响应；取消时抛出 KeyboardInterrupt。适合短脚本临时交互；复杂页面、多步骤流程请用 AppUI Form / .sheet / .alert，不要在 AppUI 回调里连续弹多个阻塞对话框。 模块概览 项 说明 导入 `import dialogs` 适合做什么 脚本开始前问一个值、危险操作确认、少量字段收集 调用时机 放在明确动作后；AppUI 里仅在按钮回调中偶尔使用 推荐顺序 `try` 调用 → 处理返回值 → `except KeyboardInterrupt` 处理取消 取消行为 用户点取消会抛 `KeyboardInterrupt`，不是返回空值 快速开始 下面脚本依次弹出输入框和列表选择： import dialogs

try:
    name = dialogs.input_alert("名称", placeholder="例如：Ada")
    mode = dialogs.list_dialog("模式", ["快速", "精确"])
    print(name, "→", mode)
except KeyboardInterrupt:
    print("用户取消") AppUI 示例 在按钮回调里触发对话框；用 try/except 处理取消，结果写回 State。 import appui
import dialogs

state = appui.State(
    message="点击按钮体验对话框",
    last_result="—",
)


def show_confirm():
    try:
        index = dialogs.alert(
            "确认操作",
            "这是一个演示对话框",
            "继续",
            "取消",
        )
        state.batch_update(
            message="用户点了确认" if index == 1 else "用户选了其他按钮",
            last_result=f"alert 返回 {index}",
        )
    except KeyboardInterrupt:
        state.batch_update(message="用户取消", last_result="alert 已取消")


def ask_name():
    try:
        name = dialogs.input_alert("你的名字", placeholder="请输入")
        state.batch_update(
            message=f"你好，{name}",
            last_result=name,
        )
    except KeyboardInterrupt:
        state.batch_update(message="输入已取消", last_result="—")


def pick_color():
    try:
        color = dialogs.list_dialog("选择颜色", ["红色", "绿色", "蓝色"])
        state.batch_update(
            message=f"已选择 {color}",
            last_result=color,
        )
    except KeyboardInterrupt:
        state.batch_update(message="选择已取消", last_result="—")


def show_hud():
    dialogs.hud_alert("已保存！", duration=1.2)
    state.message = "HUD 提示已显示"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("对话框", [
                appui.Button("确认框", action=show_confirm)
                .button_style("bordered_prominent"),
                appui.Button("输入框", action=ask_name),
                appui.Button("列表选择", action=pick_color),
                appui.Button("HUD 提示", action=show_hud),
            ]),
            appui.Section("结果", [
                appui.LabeledContent("状态", value=state.message),
                appui.LabeledContent("返回值", value=state.last_result),
            ]),
        ]).navigation_title("对话框")
    )


