background_download 后台 URLSession 大文件下载。 iOS 原生模块 连接与后台 background_download background_download background-download background_download 后台 URLSession 大文件下载：App 进入后台后仍可继续，适合较大文件。 边界 ：使用系统后台 URLSession，通过 task_id 轮询 status() 获取结果。前台小文件下载请用 network 的 download()。destination_path 需为 App 可写路径；下载启动放在按钮回调，不要在 body() 里自动发起。 模块概览 项 说明 导入 `import background_download` 适合做什么 大 JSON/媒体包后台拉取、断点续传式后台任务 调用时机 用户确认后 `download()`；用 `Timer` 或按钮轮询 `status()` 推荐顺序 `download()` 拿 `task_id` → 轮询 `status()` → 读 `path` 状态机 `running` → `completed` / `failed` / `cancelled` 快速开始 下面脚本发起下载并轮询状态： import os
import time
import background_download

dest = os.path.join(os.path.expanduser("~/Documents"), "httpbin.json")

try:
    task_id = background_download.download(
        "https://httpbin.org/json",
        dest,
    )
    print("任务:", task_id)

    for _ in range(30):
        st = background_download.status(task_id)
        print(st.get("state"), st.get("progress"))
        if st.get("state") in ("completed", "failed", "cancelled"):
            break
        time.sleep(1)

    if st.get("state") == "completed":
        print("已保存:", st.get("path"))
    elif st.get("error"):
        print("失败:", st.get("error"))
except background_download.BackgroundDownloadError as exc:
    print("下载失败:", exc, f"code={exc.code}") AppUI 示例 下载和轮询放在按钮回调；用 Timer 刷新进度状态。 import appui
import os
import background_download

DEST = os.path.join(os.path.expanduser("~/Documents"), "demo-download.json")
URL = "https://httpbin.org/json"

state = appui.State(
    task_id="",
    dl_state="空闲",
    progress="—",
    status="点击开始下载",
)


def poll():
    if not state.task_id:
        return
    try:
        st = background_download.status(state.task_id) or {}
        dl_state = st.get("state", "unknown")
        prog = st.get("progress", 0.0)
        state.batch_update(
            dl_state=dl_state,
            progress=f"{float(prog) * 100:.0f}%",
        )
        if dl_state == "completed":
            poll_timer.stop()
            state.status = f"完成: {st.get('path', DEST)}"
        elif dl_state == "failed":
            poll_timer.stop()
            state.status = f"失败: {st.get('error', '未知错误')}"
        elif dl_state == "cancelled":
            poll_timer.stop()
            state.status = "已取消"
    except background_download.BackgroundDownloadError as exc:
        poll_timer.stop()
        state.status = f"查询失败: {exc}"


poll_timer = appui.Timer(interval=0.5, repeats=True, action=poll)


def start_download():
    try:
        task_id = background_download.download(URL, DEST)
        state.batch_update(
            task_id=task_id or "",
            dl_state="running",
            progress="0%",
            status="下载中…",
        )
        poll_timer.start()
    except background_download.BackgroundDownloadError as exc:
        state.status = f"启动失败: {exc}"


def cancel_download():
    if not state.task_id:
        return
    try:
        background_download.cancel(state.task_id)
        poll_timer.stop()
        state.batch_update(dl_state="cancelled", status="已请求取消")
    except background_download.BackgroundDownloadError as exc:
        state.status = f"取消失败: {exc}"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("任务", [
                appui.LabeledContent("状态", value=state.dl_state),
                appui.LabeledContent("进度", value=state.progress),
                appui.Text(state.task_id or "—")
                .font("caption")
                .foreground_color("secondaryLabel"),
            ]),
            appui.Section("操作", [
                appui.Button("开始后台下载", action=start_download)
                .button_style("bordered_prominent"),
                appui.Button("取消", action=cancel_download, role="destructive"),
                appui.Text(state.status).foreground_color("secondaryLabel"),
            ], footer="需网络；大文件更适合后台下载。"),
        ]).navigation_title("后台下载")
    )


appui.run(body, state=state) API 参考 速查 API 作用 `download(url, destination_path, task_id)` 开始下载 → `task_id` `status(task_id)` `{state, progress, path, error}` `cancel(task_id)` 取消任务 `BackgroundDownloadError` 操作失败时抛出 download download(url, destination_path, task_id=None) task_id = background_download.download(
    "https://example.com/file.zip",
    "/path/to/save.zip",
) 参数 说明 `url` 下载地址 `destination_path` 保存路径（App 可写） `task_id` 可选自定义 ID；省略时自动生成 UUID status status(task_id) 返回： 字段 说明 `state` `running` / `completed` / `failed` / `cancelled` / `unknown` `progress` 0.0–1.0（完成时为 1.0） `path` 目标路径（完成后有效） `error` 失败时的错误信息 建议轮询间隔 ≥ 0.5 秒。 cancel cancel(task_id) — 取消进行中的任务，状态变为 cancelled。 常见错误 错误写法 后果 修正 在 `body()` 里 `download()` 刷新时重复下载 放进按钮回调 `destination_path` 不可写 移动文件失败 用 Documents 等沙盒路径 不轮询 `status()` 不知道何时完成 `Timer` 或循环查询 小文件也用后台下载 过度复杂 前台用 [network](network-module) 相关文档 文档 用途 [network](network-module) 前台 HTTP / 小文件下载 [background](background-module) 后台任务保活 [storage](storage-module) 记录 task_id 等元数据

ble_peripheral BLE 外设广播模式。 iOS 原生模块 连接与后台 ble_peripheral ble_peripheral ble-peripheral ble_peripheral BLE 外设模式：让本机作为蓝牙外设广播，供其他设备（中心端）扫描连接。 边界 ：与 bluetooth 中心端 （扫描/连接）互补——本模块做 外设广播 。需要蓝牙硬件开启；模拟器通常不可用。广播和 update_value() 放在按钮回调，不要在 body() 中自动启动。 模块概览 项 说明 导入 `import ble_peripheral` 适合做什么 传感器数据广播、简易 BLE 信标、与自定义中心 App 配对 调用时机 用户点击后开始 `start_advertising()`，离开页面时 `stop_advertising()` 推荐顺序 `start_advertising()` → `status()` 确认 → `update_value()` 推送数据 UUID `service_uuid` 必填；`characteristic_uuid` 省略时默认与 service 相同 快速开始 下面脚本启动广播、查看状态并停止： import ble_peripheral

SERVICE = "12345678-1234-1234-1234-123456789ABC"

try:
    ble_peripheral.start_advertising(
        "PyMiniApp",
        SERVICE,
        initial_value="hello",
    )
    print(ble_peripheral.status())
    ble_peripheral.update_value("ping")
    print(ble_peripheral.status())
finally:
    ble_peripheral.stop_advertising() AppUI 示例 开始/停止广播放在按钮回调；用 try/except 处理蓝牙未开启。 import appui
import ble_peripheral

SERVICE = "12345678-1234-1234-1234-123456789ABC"
DEVICE_NAME = "PyMiniApp"

state = appui.State(
    advertising=False,
    name="—",
    service="—",
    payload="hello",
    status="点击开始广播",
)


def refresh_status():
    try:
        st = ble_peripheral.status() or {}
        state.batch_update(
            advertising=bool(st.get("advertising")),
            name=st.get("name") or "—",
            service=st.get("service_uuid") or "—",
        )
    except ble_peripheral.BlePeripheralError as exc:
        state.status = f"状态查询失败: {exc}"


def start_adv():
    try:
        ble_peripheral.start_advertising(
            DEVICE_NAME,
            SERVICE,
            initial_value=state.payload,
        )
        refresh_status()
        state.status = "正在广播"
    except ble_peripheral.BlePeripheralError as exc:
        state.status = f"无法开始: {exc}（请开启蓝牙）"


def stop_adv():
    try:
        ble_peripheral.stop_advertising()
        state.batch_update(
            advertising=False,
            name="—",
            service="—",
            status="已停止广播",
        )
    except ble_peripheral.BlePeripheralError as exc:
        state.status = f"停止失败: {exc}"


def push_value():
    if not state.advertising:
        state.status = "请先开始广播"
        return
    try:
        ble_peripheral.update_value(state.payload)
        state.status = f"已推送: {state.payload}"
    except ble_peripheral.BlePeripheralError as exc:
        state.status = f"推送失败: {exc}"


def body():
    label = "停止广播" if state.advertising else "开始广播"
    return appui.NavigationStack(
        appui.Form([
            appui.Section("外设状态", [
                appui.LabeledContent("广播中", value="是" if state.advertising else "否"),
                appui.LabeledContent("名称", value=state.name),
                appui.LabeledContent("服务 UUID", value=state.service),
            ]),
            appui.Section("数据", [
                appui.TextField("特征值", text=state.payload),
                appui.Button("推送特征值", action=push_value),
            ]),
            appui.Section("操作", [
                appui.Button(label, action=stop_adv if state.advertising else start_adv)
                .button_style("bordered_prominent"),
                appui.Text(state.status).foreground_color("secondaryLabel"),
            ], footer="真机 + 蓝牙开启；中心端用 bluetooth 模块扫描连接。"),
        ]).navigation_title("BLE 外设")
    )


appui.run(body, state=state) API 参考 速查 API 作用 `start_advertising(name, service_uuid, ...)` 开始 BLE 广播 `stop_advertising()` 停止广播并清理服务 `status()` `{advertising, name, service_uuid}` `update_value(value)` 更新特征值并通知订阅方 `BlePeripheralError` 操作失败时抛出 start_advertising start_advertising(name, service_uuid, characteristic_uuid=None, initial_value=None) ble_peripheral.start_advertising(
    "SensorHub",
    "12345678-1234-1234-1234-123456789ABC",
    characteristic_uuid="ABCDEF00-0000-0000-0000-000000000001",
