network 原生 HTTP 请求、连接状态和下载。 iOS 原生模块 连接与后台 HTTP Response Download network http request download response 连接状态 network 原生 HTTP 客户端：发起 GET/POST 等请求、判断网络状态、下载文件到本地路径。 边界 ：适合 REST API 和小文件下载。大文件、后台传输或复杂上传请看系统能力规划；响应体在内存中，超大响应注意内存占用。 模块概览 项 说明 导入 `import network` 适合做什么 拉取 JSON API、提交表单、检查联网、下载文件 调用时机 放在按钮回调或加载任务；不要写在 AppUI `body()` 中 推荐顺序 `is_connected()` 提示 → `get`/`post` → 检查 `response.ok` → 解析 `json()` 蜂窝/低数据 `is_expensive()` / `is_constrained()` 为真时避免自动下大文件 快速开始 下面脚本检查网络，请求 GitHub API 并打印仓库名： import network

if not network.is_connected():
    print("当前无网络")
else:
    response = network.get(
        "https://api.github.com/repos/python/cpython",
        timeout=15,
    )
    if response.ok:
        data = response.json()
        print(data["full_name"], "⭐", data["stargazers_count"])
    else:
        print("请求失败:", response.status, response.text[:200]) AppUI 示例 请求放在按钮回调里，加载、成功、失败都写回界面。 import appui
import network

state = appui.State(
    status="未请求",
    network="—",
    detail="点击按钮开始",
)


def refresh_network_info():
    if not network.is_connected():
        state.network = "离线"
        return
    conn = network.connection_type()
    flags = []
    if network.is_expensive():
        flags.append("计费网络")
    if network.is_constrained():
        flags.append("低数据模式")
    suffix = f"（{' · '.join(flags)}）" if flags else ""
    state.network = f"{conn}{suffix}"


def fetch_repo():
    refresh_network_info()
    if not network.is_connected():
        state.batch_update(status="离线", detail="当前没有可用网络")
        return

    state.status = "请求中..."
    response = network.get(
        "https://api.github.com/repos/python/cpython",
        timeout=15,
    )
    if not response.ok:
        state.batch_update(status="请求失败", detail=str(response.status))
        return

    try:
        data = response.json()
    except Exception as error:
        state.batch_update(status="解析失败", detail=str(error))
        return

    stars = data.get("stargazers_count", "—")
    state.batch_update(
        status="请求成功",
        detail=f"{data.get('full_name', '')} · ⭐ {stars}",
    )


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("网络", [
                appui.LabeledContent("连接", value=state.network),
                appui.LabeledContent("状态", value=state.status),
                appui.Text(state.detail).foreground_color("secondaryLabel"),
            ]),
            appui.Section("操作", [
                appui.Button("获取 CPython 仓库信息", action=fetch_repo)
                .button_style("bordered_prominent"),
            ], footer="需要网络；真机测试最可靠。"),
        ]).navigation_title("网络请求")
    )


appui.run(body, state=state) API 参考 速查 API 作用 `is_connected()` 是否有可用网络 → `bool` `connection_type()` `wifi` / `cellular` / `ethernet` / `none` / `other` `is_expensive()` 是否计费网络（蜂窝/热点） `is_constrained()` 是否低数据模式 `get/post/put/delete/patch(...)` HTTP 快捷方法 → `Response` `request(method, url, ...)` 通用 HTTP 请求 `download(url, dest_path)` 下载文件 → `bool` 网络状态 import network

if network.is_connected():
    print(network.connection_type())
    if network.is_expensive():
        print("计费网络，避免大流量") API 说明 `is_connected()` 当前能否联网 `connection_type()` 连接类型字符串 `is_expensive()` 蜂窝或热点等 `is_constrained()` 系统低数据模式 HTTP 请求 request(method, url, headers=None, body=None, json=None, timeout=30) — 通用请求。 快捷方法：get、post、put、delete、patch，参数相同。 response = network.get("https://httpbin.org/get", timeout=15)
response = network.post(
    "https://httpbin.org/post",
    json={"title": "Hello"},
    headers={"Accept": "application/json"},
    timeout=20,
) Response 对象： 属性/方法 说明 `status` HTTP 状态码 `ok` `200–299` 时为 `True` `text` 响应正文字符串 `json()` 解析 JSON；非 JSON 会抛异常 `headers` 响应头字典 if response.ok:
    data = response.json()
else:
    print(response.status, response.text[:200]) 下载 download(url, dest_path, timeout=120) — 下载到本地路径，成功返回 True。 ok = network.download(
    "https://httpbin.org/json",
    "report.json",
    timeout=30,
) 下载失败返回 False；路径需脚本可写。配合 photos 的 save_video 时，先 download 再传本地路径。 常见错误 错误写法 后果 修正 在 `body()` 里发请求 每次刷新都联网 放进按钮回调 不检查 `response.ok` 把错误当成功解析 先判断 `ok` 再 `json()` 对非 JSON 直接 `json()` 解析异常 `try/except` 或改读 `text` 蜂窝网络自动下大文件 流量浪费 检查 `is_expensive()` 并提示用户 相关文档 文档 用途 [photos](photos-module) 下载视频后 `save_video` [weather](weather-module) WeatherKit 联网查询 [原生能力入口](miniapp-native-capabilities) MiniApp 场景配方

weather 当前天气与每日/每小时预报（WeatherKit）。 iOS 原生模块 连接与后台 Weather WeatherKit Forecast weather weatherkit forecast 天气 预报 温度 weather 当前天气与预报（基于 Apple WeatherKit）。支持按坐标查询、按设备位置查询，以及多日/多小时预报。 边界 ：需要 App 开启 WeatherKit 能力（Apple Developer 配置 + 带 entitlement 的签名构建）。current_location() 还需要定位权限；不包含地图或定位 UI，定位请看 location。 模块概览 项 说明 导入 `import weather` 适合做什么 天气卡片、出行建议、温度/湿度/风速展示、短期预报 调用时机 放在按钮回调或加载任务；不要写在 AppUI `body()` 中 推荐顺序 需要时申请定位 → `current` / `current_location` → 可选 `daily` / `hourly` 单位约定 温度 °C；风速 m/s；湿度 0..1；`symbol` 为 SF Symbol 名 快速开始 下面脚本按坐标查询上海当前天气，并打印未来 3 天预报： import weather

LAT, LON = 31.2304, 121.4737

try:
    now = weather.current(LAT, LON)
    print(f"{now['temperature']:.1f}°C", now["condition"], now["symbol"])
    print(f"体感 {now['feels_like']:.1f}°C · 湿度 {now['humidity']:.0%}")

    days = weather.daily(LAT, LON, days=3)
    for day in days:
        print(day["date"][:10], day["low"], "~", day["high"], "°C", day["condition"])
except weather.WeatherError as exc:
    print("查询失败:", exc, f"(code={exc.code})") AppUI 示例 天气请求放进按钮回调；结果写进 State，用 symbol 显示 SF Symbol 图标。 import appui
import permission
import weather

DEMO_LAT = 31.2304
DEMO_LON = 121.4737

state = appui.State(
    temp="—",
    summary="点击按钮开始",
    symbol="cloud",
    forecast="—",
    message="",
)


def _apply_current(now, label):
    state.temp = f"{now.get('temperature', 0):.1f}°C"
    state.summary = now.get("condition", "—")
    state.symbol = now.get("symbol", "cloud")
    state.message = f"{label}查询成功"


def _format_forecast(days):
    lines = []
    for day in days[:3]:
        date = str(day.get("date", ""))[:10]
        low = day.get("low", "—")
        high = day.get("high", "—")
        lines.append(f"{date}  {low}~{high}°C  {day.get('condition', '')}")
    return "\n".join(lines) if lines else "暂无预报"


def load_shanghai():
    try:
        now = weather.current(DEMO_LAT, DEMO_LON)
        _apply_current(now, "上海")
        state.forecast = _format_forecast(
            weather.daily(DEMO_LAT, DEMO_LON, days=3)
        )
    except weather.WeatherError as exc:
        state.message = f"查询失败: {exc} (code={exc.code})"


def load_here():
    entry = permission.status("location")
    if not entry.get("authorized"):
        permission.request("location")
        entry = permission.status("location")
    if not entry.get("authorized"):
        state.message = "需要定位权限，请先在系统弹窗中允许"
        return
    try:
        now = weather.current_location()
        _apply_current(now, "当前位置")
    except weather.WeatherError as exc:
        state.message = f"查询失败: {exc} (code={exc.code})"


def body():
    return appui.NavigationStack(
        appui.Form([
            appui.Section("当前", [
                appui.Image(system_name=state.symbol).font("largeTitle"),
                appui.LabeledContent("温度", value=state.temp),
                appui.LabeledContent("状况", value=state.summary),
            ]),
            appui.Section("操作", [
                appui.Button("查询上海天气", action=load_shanghai)
                .button_style("bordered_prominent"),
                appui.Button("查询当前位置天气", action=load_here),
            ]),
            appui.Section("3 日预报", [
                appui.Text(state.forecast).font("caption").foreground_color("secondaryLabel"),
                appui.Text(state.message).font("caption2").foreground_color("tertiaryLabel"),
            ], footer="需要 WeatherKit 能力与网络；真机测试最可靠。"),
        ]).navigation_title("天气")
    )


appui.run(body, state=state) API 参考 速查 API 作用 `current(lat, lon)` 按坐标查当前天气 → `dict` `current_location()` 按设备位置查当前天气 → `dict`（需定位权限） `daily(lat, lon, days=7)` 每日预报 → `list[dict]` `hourly(lat, lon, hours=24)` 每小时预报 → `list[dict]` `WeatherError` 查询失败时抛出的异常 当前天气 current(latitude, longitude) — 按经纬度查询。 now = weather.current(37.33, -122.03)
print(now["temperature"], now["symbol"]) current_location() — 使用设备当前位置，需先获得定位授权。 import permission

if not permission.status("location").get("authorized"):
    permission.request("location")
now = weather.current_location() 当前天气常见字段： 字段 说明 `temperature` / `feels_like` 气温 / 体感温度（°C） `condition` 天气状况文字 `symbol` SF Symbol 名，可配合 `appui.Image(system_name=...)` `humidity` 湿度（0..1） `wind_speed` 风速（m/s） `uv_index` 紫外线指数 `is_daylight` 是否白天 预报 daily(latitude, longitude, days=7) — 返回每日预报列表。 days = weather.daily(31.23, 121.47, days=5)
for day in days:
