import foundation_models

state = appui.State(
    available="—",
    prompt="用一句话介绍 PythonIDE",
    output="—",
)


def refresh_available():
    state.available = "是" if foundation_models.is_available() else "否"


def ask_model():
    refresh_available()
    if state.available != "是":
        state.output = "Foundation Models 不可用（需 iOS 26+）"
        return

    try:
