import device
import haptics
import notification
import storage

SNAPSHOT_KEY = "native.snapshot"
REMINDER_ID = "native.snapshot.reminder"

state = appui.State(
    message="就绪",
    rows=[
        {"id": "model", "title": "型号", "value": "点击刷新"},
        {"id": "battery", "title": "电量", "value": "—"},
    ],
)


def row_key(row):
    return row["id"]


def row_view(row):
    return appui.LabeledContent(row["title"], value=row["value"])


def refresh_device_info():
    state.rows = [
        {"id": "model", "title": "型号", "value": device.model()},
        {"id": "battery", "title": "电量", "value": f"{device.battery_level():.0%}"},
    ]
    state.message = "设备信息已刷新"


def save_snapshot():
    storage.set_json(SNAPSHOT_KEY, state.rows)
    if haptics.is_supported():
        haptics.notification("success")
    state.message = "快照已保存"


def remind_later():
    perm = notification.request_permission()
    if not perm.get("granted"):
        state.message = "未获得通知权限"
        return

    result = notification.schedule(
        REMINDER_ID,
        "原生快照",
        "查看已保存的设备快照",
        delay=60,
    )
    state.message = f"已调度提醒: {result}"


def body():
    return appui.NavigationStack(
        appui.List([
            appui.Section("设备", [
                appui.ForEach(state.rows, row_builder=row_view, key=row_key),
            ]),
            appui.Section("操作", [
                appui.Button("刷新设备", action=refresh_device_info),
                appui.Button("保存快照", action=save_snapshot)
                .button_style("bordered_prominent"),
                appui.Button("1 分钟后提醒", action=remind_later),
            ], footer=state.message),
        ]).navigation_title("原生能力")
    )


appui.run(body, state=state) API 参考 能力入口 能力 主文档 典型用途 定位与地图 [location](location-module) 坐标、地理编码、指南针 相册与相机 [photos](photos-module) 选图、拍照、保存 通知与实时活动 [notification](notification-module)、[live_activity](live-activity-module) 提醒、角标、锁屏状态 持久化 [storage](storage-module)、[database](database-module)、[keychain](keychain-module) 设置、记录、密钥 设备与传感器 [device](device-module)、[motion](motion-module) 屏幕、电池、传感器 触觉与声音 [haptics](haptics-module)、[sound](sound-module) 反馈、提示音 网络 [network](network-module)、[websocket](websocket-module) HTTP、实时连接 编辑器工具栏 [keyboard](keyboard-module) 插入代码片段 场景配方 目标 推荐组合 说明 选图并保存设置 `appui` + `photos` + `storage` 按钮触发 picker，路径写入 `State` 下载并存相册 `network` + `photos` 下载到本地再 `save_video` 地图展示位置 `permission` + `location` + `MapView` 先查权限再定位 健康面板 `permission` + `health` + `Chart` 拒绝时显示空状态 提醒任务 `notification` + `storage` 稳定 `identifier` 调度/取消 播放历史 `database` + `List` 大列表勿塞 `storage` 安全配置 `biometric` + `keychain` + `Form` 密钥进 keychain 传感器面板 `motion` + `haptics` 高频数据避免每帧重建 UI 远端列表 `network` + `List` + `.refreshable` 请求放刷新回调 使用规则 权限类能力先查状态，再请求。 触觉、通知、声音不要在循环里连续触发。 写代码前打开对应模块文档，按公开 Python API 调用。 常见错误 错误写法 后果 修正 在 `body()` 里请求权限/发通知 刷新时反复弹窗 放进按钮回调 token 写入 `storage` 或日志 泄露风险 用 `keychain` 权限拒绝后空白页 用户不知原因 显示说明与重试按钮 用户取消选择未处理 崩溃或脏状态 判断 `None` 并保留原状态 网络失败清空旧数据 体验差 保留缓存并显示错误 相关文档 文档 用途 [iOS 原生能力](ios-native) 入口模型、模块表与权限矩阵 [全部模块总览](modules-index) 按分类浏览模块 [运行时选择](miniapp-choose-runtime) appui / scene / widget 选型 [permission](permission-module) 统一权限查询与申请 [photos](photos-module) 相册与相机 [notification](notification-module) 本地通知

