def check_imports():
    for module, attr in BUILTIN_TRY:
        try:
            __import__(module)
            setattr(state, attr, "可导入")
        except ImportError:
            setattr(state, attr, "未内置")

    if state.numpy_ok == "可导入":
        state.hint = "数组统计可用 numpy"
    elif state.cv2_ok == "未内置":
        state.hint = "图像处理请用 vision / vision_helper / coreml"
    else:
        state.hint = "检查完成"


